package com.interview.incidentrca.service;
import com.interview.incidentrca.dto.DuplicateIncidentResponse;import com.interview.incidentrca.entity.Incident;import com.interview.incidentrca.enums.IncidentStatus;import com.interview.incidentrca.repository.IncidentRepository;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Service;import java.util.*;import java.util.stream.*;
@Service @RequiredArgsConstructor public class DuplicateDetectionService{private final IncidentRepository incidents; public List<DuplicateIncidentResponse> findDuplicates(Incident target){return incidents.findByStatusIn(List.of(IncidentStatus.OPEN,IncidentStatus.INVESTIGATING,IncidentStatus.ROOT_CAUSE_FOUND)).stream().filter(i->!Objects.equals(i.getId(),target.getId())).map(i->new DuplicateIncidentResponse(i.getId(),i.getTitle(),score(target,i))).filter(d->d.similarityScore()>=35).sorted(Comparator.comparing(DuplicateIncidentResponse::similarityScore).reversed()).limit(5).toList();} public int score(Incident a,Incident b){Set<String>x=tokens(a.getTitle()+" "+a.getDescription()+" "+a.getServiceComponent().getName());Set<String>y=tokens(b.getTitle()+" "+b.getDescription()+" "+b.getServiceComponent().getName());if(x.isEmpty()||y.isEmpty())return 0;Set<String> both=new HashSet<>(x);both.retainAll(y);Set<String> all=new HashSet<>(x);all.addAll(y);return (int)Math.round((both.size()*100.0)/all.size());} private Set<String> tokens(String s){return Arrays.stream(s.toLowerCase().split("[^a-z0-9]+" )).filter(w->w.length()>3).collect(Collectors.toSet());}}
